INSERT INTO `seo_faqs` VALUES
('1','index','Aurora Hotel Plaza ở đâu?','Where is Aurora Hotel Plaza located?','Aurora Hotel Plaza tọa lạc tại 253 Phạm Văn Thuận, Khu phố 2, Phường Tam Hiệp, TP. Biên Hòa, Tỉnh Đồng Nai.','Aurora Hotel Plaza is located at 253 Pham Van Thuan, KP2, Tam Hiep Ward, Bien Hoa City, Dong Nai Province, Vietnam.','1','1','2026-04-24 10:05:00'),
('2','index','Aurora Hotel Plaza là khách sạn mấy sao?','What star rating does Aurora Hotel Plaza have?','Aurora Hotel Plaza là khách sạn 4 sao với hồ bơi, gym, nhà hàng, spa, hội nghị.','Aurora Hotel Plaza is a 4-star hotel with swimming pool, gym, restaurant, spa, conference center.','2','1','2026-04-24 10:05:00'),
('3','index','Giá phòng Aurora Hotel Plaza là bao nhiêu?','What are the room rates at Aurora Hotel Plaza?','Giá phòng từ 1.600.000 VND/đêm (Deluxe) đến 2.300.000 VND/đêm (Suite). Căn hộ từ 800.000 VND/ngày.','Room rates from 1,600,000 VND/night (Deluxe) to 2,300,000 VND/night (Suite). Apartments from 800,000 VND/day.','3','1','2026-04-24 10:05:00'),
('4','index','Hotline Aurora Hotel Plaza?','What is Aurora Hotel Plaza hotline?','Hotline: 0251 3918 888. Email: info@aurorahotelplaza.com - Hỗ trợ 24/7.','Hotline: 0251 3918 888. Email: info@aurorahotelplaza.com - 24/7 support.','4','1','2026-04-24 10:05:00'),
('5','dat-phong','Đặt phòng Aurora có cần thanh toán trước?','Do I need to pay in advance?','Có thể thanh toán sau hoặc trả trước qua VNPay. Check-in nhanh với QR code.','Pay later or pay in advance via VNPay. Quick check-in with QR code.','1','1','2026-04-24 10:05:00'),
('6','dat-phong','Thời gian check-in/check-out Aurora?','Check-in and check-out times?','Check-in: 14:00. Check-out: 12:00. Early check-in/late check-out theo yêu cầu.','Check-in: 14:00. Check-out: 12:00. Early check-in/late check-out available upon request.','2','1','2026-04-24 10:05:00'),
('7','index','Khách sạn Aurora ở đâu tại Biên Hòa?','Where is Aurora Hotel located in Bien Hoa?','Aurora Hotel Plaza ở 253 Phạm Văn Thuận, Khu phố 2, Phường Tam Hiệp, TP. Biên Hòa, Tỉnh Đồng Nai - vị trí trung tâm, gần khu công nghiệp Amata.','Aurora Hotel Plaza is at 253 Pham Van Thuan, KP2, Tam Hiep Ward, Bien Hoa City, Dong Nai Province - central location near Amata Industrial Park.','5','1','2026-04-28 21:28:30'),
('8','index','Khách sạn Aurora gần sân bay nào?','Which airport is near Aurora Hotel?','Aurora Hotel Plaza Biên Hòa gần sân bay Long Thành (25km) và sân bay Tân Sơn Nhất (40km). Dịch vụ đưa đón sân bay có sẵn.','Aurora Hotel Plaza Bien Hoa is near Long Thanh Airport (25km) and Tan Son Nhat Airport (40km). Airport shuttle service available.','6','1','2026-04-28 21:28:30'),
('9','index','Khách sạn Aurora gần khu công nghiệp nào?','Which industrial zones are near Aurora Hotel?','Aurora Hotel Plaza Biên Hòa gần KCN Amata (3km), KCN Biên Hòa 2 (5km). Thuận tiện cho doanh nhân công tác.','Aurora Hotel Plaza Bien Hoa is near Amata Industrial Park (3km), Bien Hoa 2 Industrial Zone (5km). Convenient for business travelers.','7','1','2026-04-28 21:28:30'),
('10','index','Khách sạn 4 sao tại Biên Hòa nào tốt?','Which 4-star hotel in Bien Hoa is good?','Aurora Hotel Plaza là khách sạn 4 sao hàng đầu tại Biên Hòa, Đồng Nai với 200+ phòng, căn hộ Indochine, tiệc cưới, hội nghị.','Aurora Hotel Plaza is the premier 4-star hotel in Bien Hoa, Dong Nai with 200+ rooms, Indochine apartments, wedding venue, conference center.','8','1','2026-04-28 21:28:30'),
('11','phong-khach-san','Giá phòng khách sạn Biên Hòa Aurora?','What are room rates at Aurora Bien Hoa?','Giá phòng Aurora Hotel Plaza Biên Hòa: Deluxe từ 1.600.000 VND/đêm, Premium Deluxe từ 1.900.000 VND/đêm, VIP Suite từ 2.300.000 VND/đêm.','Aurora Hotel Plaza Bien Hoa room rates: Deluxe from 1,600,000 VND/night, Premium Deluxe from 1,900,000 VND/night, VIP Suite from 2,300,000 VND/night.','1','1','2026-04-28 21:28:30'),
('12','phong-khach-san','Phòng khách sạn Biên Hòa có view?','Do Bien Hoa hotel rooms have view?','Phòng Aurora Hotel Plaza Biên Hòa có view thành phố đẹp, phòng tầng cao có panorama. View Biên Hòa từ 14:00 check-in.','Aurora Hotel Plaza Bien Hoa rooms have beautiful city view, high-floor rooms have panorama. Bien Hoa view from 14:00 check-in.','2','1','2026-04-28 21:28:30'),
('13','can-ho','Căn hộ dịch vụ Biên Hòa giá bao nhiêu?','How much is service apartment in Bien Hoa?','Căn hộ Aurora Hotel Plaza Biên Hòa: Studio từ 800.000 VND/ngày, Premium từ 1.000.000 VND/ngày. Cho thuê dài hạn giá tốt.','Aurora Hotel Plaza Bien Hoa apartments: Studio from 800,000 VND/day, Premium from 1,000,000 VND/day. Long-term rent at good rates.','1','1','2026-04-28 21:28:30'),
('14','can-ho','Căn hộ Biên Hòa có bếp không?','Do Bien Hoa apartments have kitchen?','Căn hộ Aurora Hotel Plaza Biên Hòa có bếp đầy đủ: bếp gas, tủ lạnh, máy giặt. Tiện nghi như ở nhà.','Aurora Hotel Plaza Bien Hoa apartments have full kitchen: gas stove, fridge, washing machine. Home-like amenities.','2','1','2026-04-28 21:28:30'),
('15','wedding-service','Tiệc cưới Biên Hòa giá bao nhiêu?','How much is wedding in Bien Hoa?','Tiệc cưới Aurora Hotel Plaza Biên Hòa từ 3.500.000 VND/bàn. Menu đa dạng, sảnh sang trọng 500 khách. Hotline 0251 391.8888.','Wedding at Aurora Hotel Plaza Bien Hoa from 3,500,000 VND/table. Diverse menu, elegant hall for 500 guests. Hotline 0251 391.8888.','1','1','2026-04-28 21:28:30'),
('16','wedding-service','Sảnh tiệc cưới Biên Hòa đẹp?','Is wedding hall in Bien Hoa beautiful?','Sảnh tiệc cưới Aurora Hotel Plaza Biên Hòa sang trọng, decor đẹp, ánh sáng chuyên nghiệp. Phù hợp tiệc cưới 4 sao.','Wedding hall at Aurora Hotel Plaza Bien Hoa is elegant, beautiful decor, professional lighting. Perfect for 4-star wedding.','2','1','2026-04-28 21:28:30'),
('17','conference-service','Phòng họp Biên Hòa giá?','Meeting room price in Bien Hoa?','Phòng họp Aurora Hotel Plaza Biên Hòa từ 500.000 VND/h. Phòng 50-500 người, thiết bị hiện đại. Hotline 0251 391.8888.','Meeting room at Aurora Hotel Plaza Bien Hoa from 500,000 VND/hour. Rooms for 50-500 people, modern equipment. Hotline 0251 391.8888.','1','1','2026-04-28 21:28:30'),
('18','conference-service','Tổ chức hội nghị Biên Hòa?','How to organize conference in Bien Hoa?','Tổ chức hội nghị Aurora Hotel Plaza Biên Hòa: Đặt trước 7 ngày, menu catering, thiết bị AV. Hội nghị 4 sao chuyên nghiệp.','Organize conference at Aurora Hotel Plaza Bien Hoa: Book 7 days in advance, catering menu, AV equipment. Professional 4-star conference.','2','1','2026-04-28 21:28:30'),
('19','aurora-restaurant','Nhà hàng Biên Hòa nào ngon?','Which restaurant in Bien Hoa is good?','Nhà hàng Aurora Hotel Plaza Biên Hòa ngon: Ẩm thực Việt & quốc tế, buffet sáng, đầu bếp chuyên nghiệp. Đặt bàn 0251 391.8888.','Aurora Restaurant at Hotel Plaza Bien Hoa is delicious: Vietnamese & international cuisine, breakfast buffet, professional chef. Reserve 0251 391.8888.','1','1','2026-04-28 21:28:30'),
('20','aurora-restaurant','Buffet sáng Biên Hòa giá?','Breakfast buffet price in Bien Hoa?','Buffet sáng Aurora Hotel Plaza Biên Hòa: 150.000 VND/người. Buffet 4 sao, 50+ món Á-Âu. Từ 6:00-10:00.','Breakfast buffet at Aurora Hotel Plaza Bien Hoa: 150,000 VND/person. 4-star buffet, 50+ dishes Asian-European. From 6:00-10:00.','2','1','2026-04-28 21:28:30'),
('21','lien-he','Địa chỉ khách sạn Aurora Biên Hòa?','Aurora Hotel address in Bien Hoa?','Địa chỉ Aurora Hotel Plaza: 253 Phạm Văn Thuận, Khu phố 2, Phường Tam Hiệp, TP. Biên Hòa, Tỉnh Đồng Nai. Gần trung tâm Biên Hòa.','Aurora Hotel Plaza address: 253 Pham Van Thuan, KP2, Tam Hiep Ward, Bien Hoa City, Dong Nai Province. Near Bien Hoa center.','1','1','2026-04-28 21:28:30'),
('22','lien-he','Khách sạn Aurora Biên Hòa hotline?','Aurora Hotel Bien Hoa hotline?','Hotline Aurora Hotel Plaza Biên Hòa: 0251 391.8888. Email: info@aurorahotelplaza.com. Hỗ trợ 24/7.','Aurora Hotel Plaza Bien Hoa hotline: 0251 391.8888. Email: info@aurorahotelplaza.com. 24/7 support.','2','1','2026-04-28 21:28:30'),
('23','lien-he','Khách sạn Phạm Văn Thuận Biên Hòa?','Hotel on Pham Van Thuan Bien Hoa?','Aurora Hotel Plaza ở đường Phạm Văn Thuận 253, Biên Hòa. Vị trí đắc địa, gần khu công nghiệp, trung tâm thương mại.','Aurora Hotel Plaza is on Pham Van Thuan street 253, Bien Hoa. Prime location near industrial zones, shopping centers.','3','1','2026-04-28 21:28:30'),
('24','lien-he','Khách sạn Phường Tam Hiệp Biên Hòa?','Hotel in Tam Hiep Ward Bien Hoa?','Aurora Hotel Plaza tại Phường Tam Hiệp, Biên Hòa. Gần bến xe Biên Hòa (3km), Big C (5km), KCN Amata (3km).','Aurora Hotel Plaza in Tam Hiep Ward, Bien Hoa. Near Bien Hoa bus station (3km), Big C (5km), Amata IP (3km).','4','1','2026-04-28 21:28:30');
INSERT INTO `seo_pages` VALUES
('1','index','main','Khách sạn Aurora Plaza Biên Hòa - Khách sạn 4 sao Đồng Nai','Aurora Hotel Plaza Bien Hoa - 4-Star Hotel Dong Nai','Khách sạn Aurora Plaza 4 sao hàng đầu tại Biên Hòa, Đồng Nai. 200+ phòng nghỉ cao cấp, căn hộ Indochine, tiệc cưới, hội nghị. Đặt phòng online - Giảm 10%!','Premier 4-star hotel in Bien Hoa, Dong Nai. 200+ luxury rooms, Indochine apartments, wedding venue, conference center. Book online - 10% off!','khách sạn biên hòa, khách sạn 4 sao biên hòa, khách sạn đồng nai, aurora hotel plaza biên hòa, đặt phòng khách sạn biên hòa, khách sạn gần trung tâm biên hòa, khách sạn 4 sao đồng nai','hotel bien hoa, 4 star hotel bien hoa, hotel dong nai, aurora hotel plaza, bien hoa hotel booking, hotel near bien hoa center','/assets/img/og-image.jpg',NULL,'index, follow','1.0','daily','Hotel','1','2026-04-28 21:28:30'),
('2','phong-khach-san','main','Phòng khách sạn cao cấp Biên Hòa - Aurora Hotel Plaza','Luxury Hotel Rooms Bien Hoa - Aurora Hotel Plaza','Phòng Deluxe, Premium Deluxe, VIP Suite tại Aurora Hotel Plaza Biên Hòa. Phòng 4 sao với đầy đủ tiện nghi, view thành phố, giá hợp lý. Đặt phòng ngay!','Deluxe, Premium Deluxe, VIP Suite at Aurora Hotel Plaza Bien Hoa. 4-star rooms with full amenities, city view, reasonable rates. Book now!','phòng khách sạn biên hòa, phòng deluxe biên hòa, phòng premium biên hòa, khách sạn giá rẻ biên hòa, phòng 4 sao đồng nai, đặt phòng khách sạn biên hòa','hotel rooms bien hoa, deluxe room bien hoa, premium room bien hoa, affordable hotel bien hoa, 4 star rooms dong nai','/assets/img/og-image.jpg',NULL,'index, follow','0.9','weekly','Room','1','2026-04-28 21:28:30'),
('3','can-ho','main','Căn hộ dịch vụ cho thuê Biên Hòa - Aurora Hotel Plaza','Service Apartments for Rent Bien Hoa - Aurora Hotel Plaza','Căn hộ Studio, Indochine, Modern cho thuê dài hạn tại Biên Hòa, Đồng Nai. Căn hộ đầy đủ tiện nghi bếp, máy giặt. Liên hệ báo giá - Hotline 0251 391.8888!','Studio, Indochine, Modern apartments for long-term rent in Bien Hoa, Dong Nai. Full kitchen, laundry. Contact for quote - Hotline 0251 391.8888!','căn hộ dịch vụ biên hòa, căn hộ cho thuê biên hòa, căn hộ studio biên hòa, căn hộ indochine biên hòa, căn hộ modern đồng nai, căn hộ dài hạn biên hòa','service apartment bien hoa, apartment for rent bien hoa, studio apartment bien hoa, indochine apartment bien hoa','/assets/img/og-image.jpg',NULL,'index, follow','0.9','weekly','Apartment','1','2026-04-28 21:28:30'),
('4','dat-phong','main','Đặt phòng khách sạn Biên Hòa - Aurora Hotel Plaza','Book Hotel Bien Hoa - Aurora Hotel Plaza Online','Đặt phòng Aurora Hotel Plaza Biên Hòa online. Giá tốt nhất, thanh toán VNPay, QR code check-in nhanh. Đặt phòng khách sạn 4 sao - Hotline 0251 391.8888!','Book Aurora Hotel Plaza Bien Hoa online. Best rates, VNPay payment, quick QR check-in. Book 4-star hotel - Hotline 0251 391.8888!','đặt phòng khách sạn biên hòa, booking khách sạn biên hòa, đặt phòng aurora, đặt phòng online đồng nai, khách sạn 4 sao giá tốt','book hotel bien hoa, hotel booking bien hoa, aurora booking, online booking dong nai','/assets/img/og-image.jpg',NULL,'index, follow','0.0','daily',NULL,'1','2026-04-28 21:38:47'),
('5','dich-vu','main','Dịch vụ khách sạn Biên Hòa - Tiệc cưới, Hội nghị, Nhà hàng Aurora','Hotel Services Bien Hoa - Wedding, Conference, Restaurant Aurora','Dịch vụ Aurora Hotel Plaza Biên Hòa: Tổ chức tiệc cưới, hội nghị, nhà hàng cao cấp, cho thuê văn phòng. Dịch vụ khách sạn 4 sao - Hotline 0251 391.8888!','Aurora Hotel Plaza Bien Hoa services: Wedding venue, conference, fine dining restaurant, office rental. 4-star hotel services - Hotline 0251 391.8888!','dịch vụ khách sạn biên hòa, tiệc cưới biên hòa, hội nghị biên hòa, nhà hàng aurora biên hòa, văn phòng cho thuê biên hòa','hotel services bien hoa, wedding bien hoa, conference bien hoa, aurora restaurant bien hoa','/assets/img/og-image.jpg',NULL,'index, follow','0.8','weekly','Service','1','2026-04-28 21:28:30'),
('6','wedding-service','service','Tiệc cưới Biên Hòa - Trung tâm tiệc cưới Aurora Hotel Plaza','Wedding Venue Bien Hoa - Aurora Hotel Plaza Wedding Center','Tổ chức tiệc cưới tại Aurora Hotel Plaza Biên Hòa. Sảnh tiệc sang trọng 500 khách, menu đa dạng, trọn gói. Đặt tiệc cưới 4 sao - Hotline 0251 391.8888!','Wedding venue at Aurora Hotel Plaza Bien Hoa. Elegant hall for 500 guests, diverse menu, all-inclusive. Book 4-star wedding - Hotline 0251 391.8888!','tiệc cưới biên hòa, tổ chức tiệc cưới biên hòa, sảnh tiệc cưới biên hòa, trung tâm tiệc cưới đồng nai, tiệc cưới khách sạn 4 sao','wedding bien hoa, wedding venue bien hoa, wedding hall bien hoa, wedding center dong nai','/assets/img/og-image.jpg',NULL,'index, follow','0.7','monthly','Service','1','2026-04-28 21:28:30'),
